const b = $input.first().json.body;

// ---------- Facebook ----------
if (b.platform === 'facebook') {
  const base = 'https://graph.facebook.com/' + (b.fbApiVersion || 'v25.0');
  if (b.action === 'metrics') {
    const res = await this.helpers.httpRequest({
      method: 'GET',
      url: base + '/' + b.contentId,
      qs: {
        fields: 'created_time,shares,reactions.summary(true).limit(0),comments.summary(true).limit(0),likes.summary(true).limit(0)',
        access_token: b.fbAccessToken,
      },
      json: true,
    });
    return [{ json: { _route: 'respond', action: 'metrics', ok: true, raw: res } }];
  }
  const message = [b.title, b.description].filter(Boolean).join('\n\n');
  const res = await this.helpers.httpRequest({
    method: 'POST',
    url: base + '/' + b.fbPageId + '/feed',
    qs: { message: message, access_token: b.fbAccessToken },
    json: true,
  });
  const id = res.id;
  return [{ json: { _route: 'respond', action: 'post', ok: true, contentId: id, contentUrl: 'https://www.facebook.com/' + id, raw: res } }];
}

// ---------- YouTube ----------
if (b.action === 'metrics') {
  const res = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://www.googleapis.com/youtube/v3/videos',
    qs: { part: 'statistics,snippet', id: b.contentId },
    headers: { Authorization: 'Bearer ' + b.accessToken },
    json: true,
  });
  return [{ json: { _route: 'respond', action: 'metrics', ok: true, raw: res } }];
}
const bytes = Buffer.from(b.mediaBase64, 'base64');
const init = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://www.googleapis.com/upload/youtube/v3/videos?uploadType=resumable&part=snippet,status',
  headers: {
    Authorization: 'Bearer ' + b.accessToken,
    'Content-Type': 'application/json; charset=UTF-8',
    'X-Upload-Content-Type': b.mediaContentType || 'video/mp4',
    'X-Upload-Content-Length': String(bytes.length),
  },
  body: { snippet: { title: b.title, description: b.description || '', categoryId: '22' }, status: { privacyStatus: b.privacy || 'private', selfDeclaredMadeForKids: false } },
  json: true,
  returnFullResponse: true,
});
const location = init.headers.location || init.headers.Location;
const binaryData = await this.helpers.prepareBinaryData(bytes, 'upload.mp4', b.mediaContentType || 'video/mp4');
return [{ json: { _route: 'upload', action: 'post', location: location, contentType: b.mediaContentType || 'video/mp4' }, binary: { data: binaryData } }];
